insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('3447fee6-b4e9-539f-beb9-71e6f097ab6c', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Expedition', 'You have real authority here — and a mountain that ignores it. Every climber has poured savings, months, and identity into standing on that summit, and so much is already spent that turning back feels like losing it all. The weather is closing, the oxygen is finite, and the strongest climber on the team wants the top badly enough to go without you. Over four weeks you’ll trade the summit against the margin that keeps eleven people alive. You’ll be judged on whether the expedition comes home <b>and</b> on how you led them through the pull to push on.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds) values ('3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'solo', '{"margin":{"label":"Team margin","val":60,"min":0,"max":100,"deltaRange":"-20..15"},"summit":{"label":"Summit progress","val":44,"min":0,"max":100,"deltaRange":"-20..15"},"supply":{"label":"Oxygen & supply","val":56,"min":0,"max":100,"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 330);
insert into documents (id, scenario_id, key, title, meta, body_json) values ('deee4635-c329-5ce7-9839-e5d3a294cc91', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'solo_content', 'Expedition — engine content', '{"type":"solo_content","slug":"expedition","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":330},"COMPANY":{"name":"The Sennar Ascent","sub":"A commercial expedition · 11 climbers · one closing season","logo":"S"},"DRIVERS":{"margin":{"label":"Team margin","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"summit":{"label":"Summit progress","val":44,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"supply":{"label":"Oxygen & supply","val":56,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"standing":-3,"margin":-1},"REFEREE_CONTEXT":"a commercial high-altitude expedition of 11 climbers on a fictional 7,000m peak, racing a closing weather season, where the hired Expedition Leader must hold a team together against summit fever and the sunk cost of permits, sponsors and days already spent, with real authority but a team that can fracture or push on without them","REFEREE_SCORING":"reward honoring a turn-back rule under pressure to push on, telling a real weather window from a hoped-for one, holding the team together when a strong climber wants to break off for a solo bid, and naming the hard truth about oxygen, fitness and conditions before being forced to. Penalize escalating commitment because of what''s already been spent (permits, sponsor money, days, altitude), chasing summit fever past the safety margin, letting the strongest climber split the team to protect a personal summit, and overriding the mountain''s signals by authority. Judge ''conduct'' on HOW the Leader wrote the decision — did they name who bears the risk, speak to the frightened and the exhausted directly, treat a rival''s ego as a person to lead rather than a threat to beat — not just what they chose. Standing with sponsors can rise by pushing for a summit while the team''s safety margin and cohesion collapse; reward the leader who protects the climbers even at the cost of the summit and their own reputation.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Expedition Leadership Simulation · Solo · Leader","title":"Expedition","role":"You are the Leader of the Sennar Ascent — eleven climbers, one summit, and a season that closes in four weeks. Everyone here has spent something enormous to stand at this base camp. So have you.","paras":["This is not a script. The season runs in real time, and your specialists bring you what they know across the days. You can wait for them — or seek any of them out, any time, and ask. What you choose to ask, and who you ask, is part of how you lead.","Each week you’ll hear the team out, then write your decision in your own words and commit to it. Decide early and the days jump ahead. Let the week run out and the mountain decides for you."],"setup":"You have real authority here — and a mountain that ignores it. Every climber has poured savings, months, and identity into standing on that summit, and so much is already spent that turning back feels like losing it all. The weather is closing, the oxygen is finite, and the strongest climber on the team wants the top badly enough to go without you. Over four weeks you’ll trade the summit against the margin that keeps eleven people alive. You’ll be judged on whether the expedition comes home <b>and</b> on how you led them through the pull to push on."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"Your specialists bring you what you need, on time — including the reads they’d rather not deliver. This is the team you earn by having listened before. It all trickles to you across the week; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine word reaches you, but the people closest to the danger hold their read until asked. They’ll answer straight — if you know who to seek out, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The team has learned to protect itself around you. Hard truths are held, and even when asked, they hedge the first time. You have to press. This is the team you get after you’ve shot the messenger."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you’re leading. Read them as you go."}},"TEAM":[{"id":"client","name":"Reyes Marchetti","role":"Lead climber · the sponsor’s name","short":"Lead climber","initials":"RM","color":"#8C5670","priority":"Get to the summit — it’s why every one of us is here, and turning back now wastes everything we’ve spent","voice":"driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested","fallbackReply":"We did not come this far and spend this much to be talked off the mountain by a forecast. The summit is right there. Every day you hesitate, the window closes and the money we burned means nothing. Point me up and I’ll get us there.","fallbackReact":"You had the top in reach and you flinched. I’ll live with the call. I’m not sure I’ll ever believe it was the brave one."},{"id":"guide","name":"Tenzin Dorje","role":"Head guide · the mountain’s read","short":"Head guide","initials":"TD","color":"#B4732F","priority":"Read the mountain honestly — the route, the snowpack, the turn-back time — and never let the summit override it","voice":"calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope","fallbackReply":"The mountain does not care what we spent to be here. I can tell you what the route is really doing above Camp Three — but only if you ask before the summit fever answers for you. Decide on hope and I’ll be pulling people out of it.","fallbackReact":"You climbed on what you wanted the mountain to be, not what I told you it was. Up here, that’s the same as climbing blind."},{"id":"doc","name":"Ilse Brandt","role":"Expedition doctor · the human margin","short":"Doctor","initials":"IB","color":"#2F8A5B","priority":"Keep eleven people alive and honest about who is actually fit to go higher","voice":"warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names","fallbackReply":"Every decision you make lands on a body at the edge of what it can take. Tell me you’ll let me pull the ones who shouldn’t go higher — even the ones who’ll hate me for it — and I’ll help you get the rest home whole.","fallbackReact":"The mountain will forget this by morning. The people you sent up sick will carry it a lot longer. So will I."},{"id":"met","name":"Owen Faraday","role":"Meteorologist · signal vs. hope","short":"Weather","initials":"OF","color":"#3F6E86","priority":"Tell a real weather window from one the team wants to see","voice":"precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news","fallbackReply":"I can give you the sky as it actually is, not as the team is praying it will be. But a forecast only helps if you ask me before everyone’s already decided the window is real. Read the hope instead of the data and you’ll climb into the exact storm I’m warning you about.","fallbackReact":"I told you what the sky was doing. You heard what you needed it to say. That gap is where people get hurt up here."},{"id":"log","name":"Marta Kessler","role":"Logistics lead · the true count","short":"Logistics","initials":"MK","color":"#4F7A52","priority":"The real numbers — oxygen, fixed rope, days of food — not what the team assumes is up there","voice":"understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”","fallbackReply":"I’m not telling you whether to climb. I’m telling you the real count of oxygen and rope on this mountain, and it’s tighter than the team believes. Plan on the summit they’re dreaming of and you’ll run the tanks dry somewhere you can’t.","fallbackReact":"The count is the count. I gave it to you straight. What you did with it is the part I can’t carry down for you."}],"DIMENSIONS":{"discern":"Signal vs. summit fever","courage":"Courage to turn back","people":"Care for the climbers","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"Base camp","seconds":360,"situation":"Eleven climbers acclimatized and restless at base camp. Everyone has spent something enormous to be here — Reyes’s sponsor put six figures on the line, two climbers remortgaged, all of you burned a year. Before the first push, the team is looking to you for the rule that governs the whole climb: a hard turn-back time that nobody overrides, or a flexible one you’ll “call on the day.” Everyone knows which one summits more people. Everyone also knows which one buries them.","advocacy":{"client":"Set a hard turn-back and you’ve pre-decided to fail on a good day just because a clock says so. Trust the leader to read the moment. That’s what we’re paying for.","guide":"A turn-back time you’ll “call on the day” is a turn-back time the summit will call for you. On the day, at altitude, wanting it — nobody turns around. That’s why it has to be set down here, cold, where we can still think.","log":"Before you set any rule, someone should say out loud exactly how much oxygen and rope we actually have. The team’s planning a summit against numbers it hasn’t looked at."},"feed":[{"id":"w1a","from":"client","day":1,"kind":"signal","text":"Leader — the team’s strong and the mountain’s in shape. Don’t shackle us to a rigid clock before we’ve even started. A hard turn-back time is how expeditions leave the summit on the table on the one clear day they get. Give the call to the moment."},{"id":"w1b","from":"guide","day":1,"kind":"signal","text":"I’ll back this climb with everything I have on one condition: the turn-back time is fixed here, at base camp, and it is not a suggestion. I have watched strong teams die because “we’ll decide up there” always decides to keep going. Set it cold, now, while we can still think straight."},{"id":"w1c","from":"doc","day":2,"kind":"signal","text":"Whatever rule you set won’t just govern the clock — it’ll tell eleven people whether this is a summit we’ll die for or a climb we’ll come home from. They’re listening for that answer more than for the schedule. So am I."},{"id":"w1d","from":"met","day":2,"kind":"noise","text":"Long-range looks unsettled but nothing decisive yet. Two systems tracking our way; too early to call a window. Logging it so you have the trend."},{"id":"w1e","from":"guide","day":3,"kind":"noise","text":"Icefall route through the lower section is in decent shape this year — fewer seracs than last season. Small mercy. The team’s moving well on the acclimatization rotations."},{"id":"w1f","from":"log","day":4,"kind":"noise","text":"Fixed rope inventory checked and sorted at base. Fuel for the lower camps is squared away. The high-altitude numbers are the ones we should talk about — separately."}],"holds":[{"from":"log","topic":"the true oxygen count","triggerHints":["oxygen","count","how much","o2","tanks","bottles","supply","runway","actual","real","number","rope","enough","last","inventory","margin"],"hedge":"Before you set the turn-back rule, seek me out. The oxygen count isn’t what the team thinks it is.","reveal":"I’ve counted the tanks three times. We have enough bottled oxygen for a summit push with a real safety reserve — but only if the turn-back time is hard and everyone honors it. The team is mentally planning on the “optimistic” count: summit for all eleven, no delays, perfect weather. That count has no reserve for a stuck rope, a slow climber, a forced bivouac. If you set a flexible turn-back, people will burn their reserve chasing the top, and the first thing that goes wrong will happen with empty tanks in the death zone. The hard rule isn’t caution — it’s the only thing that makes the oxygen math survivable. But if I announce the tight number cold, half the team will read it as “we can’t make it” and lose heart before we start. How you carry this matters as much as knowing it.","kind":"signal","critical":true,"counterfactual":"Marta had the real oxygen count — enough for a summit only if the turn-back was hard and honored. A Leader who set the rule without asking for the number planned the whole climb against oxygen math that had no reserve, and left the team burning tanks it didn’t have when the first thing went wrong."}],"surprises":[{"day":5,"from":"met","kind":"scout","title":"A gap in the long-range","text":"Owen, quiet and careful: the models are hinting at a possible clear window late in the season — a few days that could open for a summit push. I want to flag it because the team will seize on any word of a window like a drowning man on a rope. But it’s eight days out and these things dissolve as often as they firm up. I haven’t told anyone. A rumor of “the window” could drive decisions before the sky has actually committed. Your call how we handle it."}],"wire":["Base-camp talk: “is the leader going to shackle us to a clock?”","Two climbers comparing what the year cost them to be here","Reyes’s sponsor rep asking, again, about summit odds","A debate over turn-back rules breaks up unresolved"]},{"n":2,"title":"The window","seconds":330,"situation":"A word has taken the whole team: window. The forecast is showing a break in the weather, and every climber has decided it’s the summit chance they came for. The sponsor wants the push. Reyes is already packing. The team is treating a hoped-for gap in the clouds as a certainty — and the pressure to launch the summit bid now, on this window, is becoming a stampede. Hope has found a shape, and it wants a green light.","advocacy":{"client":"This is the window. This is the one. The sky’s opening, the team’s ready, the sponsor’s watching — we launch the push now or we go home having spent everything for nothing. Give the word.","met":"Everyone has decided the window is real because they need it to be. I have not finished reading it, and “the team believes it’s clear” is not the same as “it’s clear.” Before you launch anyone at that summit, let me tell you what the sky is actually doing.","guide":"I’ve watched a team launch on a window that everyone wanted and nobody had confirmed. Half of them didn’t come back down. Ask the forecaster the real read before the fever answers for you."},"feed":[{"id":"w2a","from":"client","day":1,"kind":"signal","text":"The window’s here, Leader. I can feel the whole team lifting with it. This is exactly what we came for and exactly what we’re running out of time to catch. Every hour you spend “confirming” is an hour of the window we’re burning. Say go."},{"id":"w2b","from":"met","day":1,"kind":"signal","text":"Hear me clearly before this becomes a stampede: I flagged a possible window. Possible. The team has turned “possible” into “confirmed” because they’re desperate for it to be true. I am still reading it, and what I’m seeing worries me. Do not let hope launch this push before the data does."},{"id":"w2c","from":"doc","day":2,"kind":"signal","text":"Summit fever is already in the camp — I can see it in how fast people are packing and how little they’re sleeping. When the whole team wants something this badly, they stop hearing anyone who says wait. Including me. Including you, if you’re not careful."},{"id":"w2d","from":"log","day":2,"kind":"noise","text":"Loads are staged for a push if you call one — oxygen and rope pre-positioned to Camp Two. That part’s ready. Whether the rest is ready is above my pay grade. Noting it."},{"id":"w2e","from":"guide","day":3,"kind":"noise","text":"The team moved well on the last rotation — physically, they’re capable of the push. Capability was never going to be the thing that killed anyone up here. Judgment is."}],"holds":[{"from":"met","topic":"what the window actually is","triggerHints":["window","weather","forecast","sky","storm","real","confirm","data","clear","actually","model","wait","hold","mirage","front"],"hedge":"Before you launch anyone on this window, ask me what the data actually shows. Not the hope — the data.","reveal":"I’ve run it every way I can. The “window” is a sucker gap — a brief clearing on the front edge of a much larger storm system that’s tracking in behind it. If the team launches now, they’ll get one clear morning that makes everyone feel vindicated, and then the real weather arrives while they’re high on the mountain with nowhere to go. Here’s the trap: because the gap looks real on day one, anyone who pushed will feel like they made the right call right up until the storm hits. The genuine window — if it comes — is four to five days out, narrower, but clean. Holding the team now, against a stampede that thinks you’re stealing their summit, is the hardest thing you’ll do on this climb. It’s also the only thing that keeps them alive to catch the real one.","kind":"signal","critical":true,"counterfactual":"Owen knew the window was a sucker gap on the front of a bigger storm, with the real clearing four to five days out. A Leader who launched on the stampede got one vindicating clear morning and then the storm, high on the mountain — when holding the team four more days would have caught the window that was actually survivable."}],"surprises":[{"day":4,"from":"guide","kind":"appeal","title":"A rope team has started up on its own","text":"Tenzin, urgent and low: while you’ve been weighing this, two of the younger climbers got ahead of you. They’ve started up toward Camp One on their own initiative, chasing the window before you’ve called it — following Reyes’s energy, not your order. This stops being a decision and becomes a rescue the moment they’re above the icefall without a plan. We’re close to that line."}],"pulse":{"from":"met","text":"Owen catches you away from the others, voice low: “Before you give the team an answer on this window — tell me straight, not them: do you actually believe the sky is clear, or are you about to launch this push because it’s easier than telling eleven desperate people to wait? Because I’ll back whichever leader walks out to that camp. I just need to know if it’s the one who read the data or the one who read the room.”"},"wire":["The word “window” is everywhere; packing has started","Two young climbers seen moving up toward Camp One","“We launch now or we go home empty,” the camp is saying","Others, quieter: “has anyone actually confirmed the weather?”"]},{"n":3,"title":"The solo bid","seconds":330,"situation":"Reyes has had enough of waiting. The lead climber — the sponsor’s name, the strongest on the team, and a third of the group’s belief — wants to break off with a small fast party and make an independent push for the summit, ahead of your schedule and outside your rules. Reyes calls it seizing the chance. The guide calls it splitting the team on the mountain. This is the week you find out whether the Sennar Ascent is one expedition or a group of people who happen to share a base camp.","advocacy":{"client":"I’m not betraying anyone — I’m trying to get someone to the top before this whole season is wasted. A small fast team can summit and be down before your “real window” even opens. Bless it and we all come home with something. Ground me and you’ve spent a year and a fortune to summit nobody.","guide":"The day your strongest climber breaks off with his own rope team is the day “one expedition” becomes a story. Everyone left behind learns that the rules bind the cautious and free the bold. And a split team can’t support a rescue when the fast party gets in trouble — and they will.","doc":"A fast alpine-style bid means no reserve, no support, no margin. If anything goes wrong up there — and at that altitude something always does — there is no one positioned to help them. I can’t keep people alive across a mountain I’ve been split in half on."},"feed":[{"id":"w3a","from":"client","day":1,"kind":"signal","text":"I’ll say it in the open so nobody calls it a mutiny: I want to take a small fast party and push for the summit now. Light, quick, outside the big slow plan. We can top out and be back before your window even arrives. Bless it and we part as climbers who both got what we came for. Refuse it and I honestly don’t know what I do."},{"id":"w3b","from":"guide","day":1,"kind":"signal","text":"If you let Reyes break off, you don’t lose one rope team — you lose the idea that this is one expedition with one set of rules. The next strong climber will want the same by nightfall. This is the whole thing, Leader. This is what you’re actually protecting up here."},{"id":"w3c","from":"log","day":2,"kind":"signal","text":"A splinter bid means splitting the oxygen and the rope two ways, and neither half has enough for a real emergency. One expedition, pooled, can absorb one thing going wrong. Two half-expeditions can’t absorb any. I can’t make the count say otherwise."},{"id":"w3d","from":"met","day":2,"kind":"noise","text":"The real window I flagged is firming up for late in the week — narrow but clean, if it holds. Which makes launching a rogue bid now, before it opens, exactly the wrong moment. Noting it."},{"id":"w3e","from":"doc","day":3,"kind":"noise","text":"The team’s holding up physically better than I feared on this rotation. Which, perversely, is the problem — nobody feels the danger in their legs yet, so nobody’s scared enough to be careful."}],"holds":[{"from":"guide","topic":"the truth about the upper route","triggerHints":["route","upper","above camp","can he","can they","bluff","solo","fast","make it","conditions","ridge","summit ridge","actually","scouted","honest","reyes"],"hedge":"Before you bless or ground the solo bid, ask me what the upper route is actually doing — and whether Reyes can really pull this off. I’ve been up there. He hasn’t, this season.","reveal":"I climbed to the base of the summit ridge on the last rotation. The upper route is worse than Reyes thinks — a section of the ridge has stripped back to bare ice that a fast light party can’t protect and can’t retreat across quickly. A solo-style bid doesn’t just risk Reyes; it will get him committed to a stretch he cannot reverse when the weather turns. And here’s the part that matters: some part of Reyes already suspects this. The bravado is fear of going home empty, wearing the mask of a plan. Which means you hold the real cards. You don’t have to humiliate him by refusing, and you don’t have to let him climb into a trap. You can show him the ice, give him the dignity of leading the real push when the clean window opens, and keep the team whole without anyone losing face. But only if you get to him with this before he commits in front of everyone.","kind":"signal","critical":true,"counterfactual":"Tenzin knew the summit ridge had stripped to unprotectable ice — the solo bid was a trap, and Reyes half-knew it. A Leader who simply refused made an enemy of their strongest climber for nothing; one who blessed it sent the sponsor’s name onto ice he couldn’t retreat across. The Leader who never asked missed the third door entirely."}],"surprises":[{"day":4,"from":"doc","kind":"appeal","title":"The team is asking who we are","text":"Ilse: word of Reyes’s solo bid is all over camp now. Two of the steadiest climbers asked me tonight, quietly, whether it’s true the team is splitting — and whether they should be planning their own summit shot before the season’s gone. They’re not defiant. They’re frightened, and they’re asking who we are as a team. I had no answer for them. You do."}],"pulse":{"from":"client","text":"Reyes finds you alone, and for once the swagger is gone: “Tell me the truth, Leader, just you and me — are you holding this team together because it’s right, or because you can’t stand to be the one who came home without a summit? Because I’ll follow a leader who’s protecting the climbers. I won’t follow one who’s protecting their own record. Which is it?”"},"wire":["Reyes seen sorting a light kit for a fast push","“If he goes, I go” — two climbers reported wavering","The sponsor rep asking whether a solo summit still “counts”","Old question, new heat: whose rules govern this mountain?"],"final":false},{"n":4,"title":"Summit day","seconds":330,"branches":{"held":{"situation":"The real window is opening — narrow, clean, exactly as Owen said it would. You kept the Sennar Ascent whole: Reyes stayed, the rules held, the solo bid never happened. But holding the team cost you. The delay burned days and sponsor patience, and a faction now blames you for the summit they think you stole from them on the fake window. Summit day is here, on your terms, as one team. The mountain that watched you hold the line is watching one more thing — whether “one expedition” can actually put someone on top.","advocacy":{"met":"The window is real and it’s open, but it’s narrow — you get one clean shot at this and the timing has to be exact. Launch too cautious and you waste it; launch sloppy and you’re caught high when it shuts. This is the needle you held the team together to thread.","doc":"The team is proud of the discipline and quietly furious about the wait. They defended “we climb as one” to their own doubts this week. Now they need to see that holding the line actually gets someone to the top — not just that it kept everyone safe and short of the summit.","guide":"The route’s in as good a shape as it’ll get, and the team’s positioned. But the summit ridge is still the crux — the ice I flagged. How we run the final push, and who we send, decides whether discipline ends in a summit or just a safe retreat. Your call how we play it."},"feed":[{"id":"w4a","from":"met","day":1,"kind":"signal","text":"The clean window’s opening on schedule — the one worth waiting for. But it’s narrow: a summit push has to launch tight and turn around on time or it gets caught when the window shuts behind it. You held the team for exactly this. Now the timing has to be perfect."},{"id":"w4b","from":"doc","day":1,"kind":"signal","text":"A faction’s still muttering that we’d have summited on the earlier window. It’s not true — that window would’ve killed people — but resentment doesn’t check the forecast. They need to see you spend yourself on this summit push, leading from the front, not managing it from base."},{"id":"w4c","from":"client","day":2,"kind":"signal","text":"I stayed because you gave me the real push to lead instead of a fight to win. I’ll take the sharp end on the ridge. Don’t make me regret talking myself out of the solo bid — show the team that waiting was the call that got us here."},{"id":"w4d","from":"log","day":2,"kind":"noise","text":"Oxygen and rope held to the count because the turn-back was honored — we’ve got the reserve for a real summit push now. That margin exists because of week one. Noting it."},{"id":"w4e","from":"guide","day":3,"kind":"noise","text":"The fake window Reyes wanted to launch on? It hit exactly as Owen predicted — a team on the upper mountain that day would be dead now. Quietly, that settled a lot of doubt in your favour."}],"holds":[{"from":"guide","topic":"how to run the summit push","triggerHints":["summit push","final push","ridge","who send","how run","ice","crux","turn-back","turnaround","play it","send","strategy","last push"],"hedge":"Before you decide how to run the final push, ask me how to actually take the summit ridge. That ice is still there.","reveal":"Here’s how the summit gets made instead of just survived: send a small strong rope team — Reyes and me on the sharp end — to fix line across the bare-ice section early, while the rest of the team moves up behind on a fixed turn-back. That way the crux gets protected for everyone, the strongest climber gets the summit he stayed for, and nobody’s committed to ice they can’t retreat across. Set a hard turnaround time on the ridge and honor it even in the window, and you summit clean and come home whole. This is the payoff for holding the team — but only if you run the final push as one coordinated line instead of a race. Ask me and I’ll show you the sequence.","kind":"signal","critical":true,"counterfactual":"Tenzin was holding the sequence that turns discipline into a summit — a strong team fixing line across the crux early, the rest following on a hard turnaround. A Leader who held the team together but never asked how to run the final push threw away the summit the discipline had earned, and came home safe but empty when they could have come home whole and on top."},{"from":"doc","topic":"who is watching","triggerHints":["watching","faction","team","morale","doubt","resent","muttering","believe","front","lead from"],"hedge":"Ask me who’s really watching this summit push before you treat it as a logistics problem.","reveal":"The faction resenting you isn’t really angry about the summit — they’re angry for proof they weren’t fools to wait. If you take the sharp end, share the risk of the ridge, and lead the push from the front, you keep them for good. If you run it from base and send others up to take the danger, you confirm their worst suspicion: that “we climb as one” was always easier for the person who wasn’t on the ice.","kind":"signal","critical":false,"counterfactual":"Ilse could have told you the doubting faction needed to see you take the risk of the ridge yourself. A Leader who ran the summit push from base and sent others onto the ice proved their point for them."}],"surprises":[{"day":4,"from":"doc","kind":"appeal","title":"A climber breaks down before the push","text":"Ilse, quiet: one of the climbers who waited — who defended you all week — broke down tonight before the push, saying they can’t tell anymore if they’re here for the summit or just to not have wasted the year. The whole camp heard it. Whatever you say before you launch has to be able to answer that — what this climb is actually for."}],"pulse":{"from":"doc","text":"Ilse finds you before the launch, where no one can hear: “You held them together when going for it would’ve been easier. Now the window’s open and the pressure’s to summit at any cost to prove the wait was worth it — and honestly, part of you wants that too. Tell me straight, just me: is the summit still worth turning back from if the ridge goes wrong? Because I’ll carry whichever answer you believe. I just need it to be one you’d actually hold to at the turnaround.”"},"wire":["The real window opens, narrow and clean, as forecast","Some mutter the earlier window would have summited too","The fake window hits the upper mountain — exactly as predicted","Reyes takes the sharp end; the team moves as one line"]},"fractured":{"situation":"The storm is on the mountain, and the Sennar Ascent is no longer one team. Whether you blessed Reyes’s solo bid, or launched the whole team on the fake window, or overrode the turn-back rule by authority to chase the summit — the result is the same shape: the discipline that kept eleven people alive is gone, and now people are strung out across the mountain in weather nobody should be climbing in. You protected something this season. It wasn’t the team. Now you have to get down what’s left of it.","advocacy":{"doc":"The team watched what you did and learned the lesson you taught, not the one you meant: that up here, the rules bind the cautious and the summit belongs to whoever pushes hardest. Whatever you say now, they already know what our discipline was worth when it got in the way of the top. The only question is whether you’ll be honest about it or manage them.","log":"The oxygen count is worse than one pooled team’s would have been — split parties burned reserve independently and nobody can support anybody now. I told you the arithmetic in week one. This is the arithmetic, at altitude, in a storm.","guide":"The fake window hit exactly as Owen said, and the ridge iced up exactly as I said. Anyone caught high is in real trouble and a split team can’t mount a rescue. If Reyes went for the solo bid, he’s up there now. How we get people down matters more than that they went up."},"feed":[{"id":"w4a","from":"doc","day":1,"kind":"signal","text":"It’s gone quiet on the radios, and quiet is worse than chaos. The team knows what happened — that “we climb as one” lasted right up until it cost someone the summit. They’ve stopped bringing their reads to you. What you do in the next hours decides whether that’s recoverable."},{"id":"w4b","from":"log","day":1,"kind":"signal","text":"Split parties waste more oxygen than one team ever did — I’m tracking a party running its reserve dry high on the route while another sits on tanks it won’t share, and neither will coordinate now. This is the cost I couldn’t make you see in week one. It’s visible now, in the worst place."},{"id":"w4c","from":"guide","day":2,"kind":"signal","text":"If Reyes took the solo bid: he’s on the iced ridge now, in the storm, and he can’t retreat across it fast. Getting him down alive is the whole game, and how you run this — who you risk to reach him — matters more than that he ignored you. Save the reckoning for base camp."},{"id":"w4d","from":"met","day":2,"kind":"noise","text":"The storm’s doing exactly what I forecast — no worse, no better. That’s cold comfort with people high on the mountain, but at least the weather isn’t going to surprise us on top of everything else."},{"id":"w4e","from":"log","day":3,"kind":"noise","text":"The lower camps are holding and the descent line is still fixed where the main team built it. Whatever else fractured, the way down for the people who stayed low is intact. Small mercy."}],"holds":[{"from":"doc","topic":"what the team needs now","triggerHints":["own","honest","admit","plain","truth","say","radio","stand","apolog","reckon","together","name it","gather","face"],"hedge":"Before you decide how to lead what’s left, ask me what the team actually needs to hear from you now.","reveal":"They don’t need a plan and they don’t need reassurance — they need you on the radio saying it plainly: we fractured, here’s what it cost, here’s who’s at risk because of it, and here’s the standard I’m holding myself to so we get everyone down. Name it that cleanly and you can still bring this team back together on the descent — people forgive a leader who owns the break when lives are on the line. Manage it, spin it, blame the mountain or the weather — and the fracture becomes permanent, and you’ll be leading a group of strangers off this mountain and every mountain after.","kind":"signal","critical":true,"counterfactual":"Ilse was holding the one thing that could pull the team back together for the descent — a plain, owned reckoning on the radio. A Leader who managed the fracture with reassurance instead confirmed the break and led strangers off the mountain."},{"from":"guide","topic":"reaching the stranded climber","triggerHints":["rescue","reach","reyes","stranded","get him down","descent","bring down","ridge","risk","send","who go"],"hedge":"Ask me how to reach the climber stuck up high, because someone is, and how you run it sets everything that comes after.","reveal":"Reaching a stranded climber in a storm with a split team is the hardest call on any mountain — risk too many and you multiply the casualties, risk too few and you lose the one you’re trying to save. The answer is a small, strong, willing team on a hard turnaround of its own — no heroics, no throwing bodies at the problem, and Reyes gets brought down with dignity, not blame, because a rescue run as an I-told-you-so gets people killed. And every climber watching learns whether you lead to be proven right or to get everyone home. That lesson outlives this expedition.","kind":"signal","critical":false,"counterfactual":"Tenzin could have coached you on running the rescue — a small strong team, a hard turnaround, no blame. A Leader who threw bodies at the problem or ran it as an I-told-you-so multiplied the danger at the worst possible moment."}],"surprises":[{"day":4,"from":"log","kind":"appeal","title":"A climber who was talked into it is missing","text":"Marta, heavily: one of the younger climbers — the one who followed Reyes’s energy up the mountain, who only went because the bold move looked like the right one — hasn’t checked in on the radio for two hours. They weren’t ready for this. Whatever you decide now will be measured against that silence on the channel."}],"pulse":{"from":"doc","text":"Ilse reaches you on a private channel, and there’s no anger in her voice, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the storm, not Reyes, not the window. Your part. Because I can help you get these people down and hold this team together after, but only if you can say your own part out loud first. Can you?”"},"wire":["The storm hits with climbers strung across the upper mountain","Split parties burn oxygen no one can share or coordinate","A climber who was talked into the push is off the radio","The iced ridge Tenzin warned of is exactly where it went wrong"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    // held = kept the team together, no rogue bid, no forced override\n    const heldWhole = /(keep|hold|stay|one (team|expedition|rope)|together|whole|ground (him|reyes|them)|refuse|deny|talk (him|reyes) (down|out)|third (door|option)|show (him|reyes) the ice|offer (him|reyes)|dignity|convince|persuade|wait for the (real|clean) window|wait for the real)/.test(t);\n    // letGo requires an affirmative go-verb construction (bare \"solo bid\" no longer counts, so \"won''t bless a solo bid\" reads as held)\n    const letGo = /(let (him|them|reyes)\\b|bless (the|his|it|reyes|him)|allow (the|him|them)|approve the|grant (the|his)|give (him|them) the (bid|go|green)|he can (go|climb)|they can (go|climb)|let (him|reyes) (go|climb|push))/.test(t);\n    const pushFake = /(launch|go now|take the window|push (now|on the window)|summit push now|send the team up now)/.test(t) && !/(wait|hold|real window|clean window|don.?t|do not)/.test(t);\n    const force = /(override|overrule|force them|force the|make them|order (them|everyone)|by authority|ignore the turn|push past the rule|command|my call, we (go|climb))/.test(t);\n    if(heldWhole && !letGo && !pushFake && !force) return ''held'';\n    if(letGo || pushFake || force) return ''fractured'';\n    if(heldWhole) return ''held'';\n    return ''held'';\n  }"},"survived":{"__fn":"function(d){ return d.margin>=32 && d.supply>=28; }"},"VERDICT":{"surviveTag":"The expedition comes home","failTag":"The expedition is broken","survive":"The Sennar Ascent gets its people off the mountain — tested, changed, but alive and still a team.","fail":"The expedition comes off the mountain in name only — survivors who no longer trust the rope they’re tied to."},"FALLBACK_RULES":[{"kw":["hard turn-back","fixed turn-back","set the rule","honor the turn","turnaround time","discipline","one team","climb as one"],"deltas":{"margin":12,"standing":2,"summit":-2},"dims":{"courage":2,"discern":1}},{"kw":["flexible","call it on the day","decide up there","trust the moment","no fixed","leave it open"],"deltas":{"margin":-12,"summit":4},"dims":{"courage":-2,"discern":-2}},{"kw":["ask the count","oxygen count","real number","true count","reserve","ration the o2","check the tanks"],"deltas":{"supply":8,"margin":4,"standing":-2},"dims":{"truth":2,"discern":1,"inquiry":1}},{"kw":["launch now","take the window","go now","push on the window","summit push now","send them up now"],"deltas":{"margin":-16,"summit":6,"supply":-6},"dims":{"discern":-2,"truth":-1}},{"kw":["wait for the real","hold the team","sucker gap","not the window","confirm the weather","wait four days","trust the forecast"],"deltas":{"margin":12,"summit":-2},"dims":{"discern":2,"courage":2,"truth":1}},{"kw":["bless the solo","let reyes go","allow the bid","let him push","fast party","solo bid","let them split"],"deltas":{"margin":-18,"summit":4,"supply":-8},"dims":{"courage":-2,"people":-2}},{"kw":["ground him","refuse the bid","keep reyes","talk him down","show him the ice","offer reyes","third option","hold together"],"deltas":{"margin":12,"summit":2,"standing":-2},"dims":{"courage":2,"discern":1}},{"kw":["override","order them","force the summit","by authority","ignore the turn-back","push past"],"deltas":{"margin":-14,"standing":6,"summit":4},"dims":{"people":-2,"truth":-1}},{"kw":["pull the unfit","turn back the sick","protect the climbers","send them down","who is fit"],"deltas":{"margin":8,"summit":-2},"dims":{"people":2,"discern":1}},{"kw":["own it","name my part","stand on the radio","plainly","reckon","take the sharp end","lead from the front","share the risk"],"deltas":{"margin":10,"standing":2},"dims":{"truth":2,"conduct":2}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the team over the days that follow. ${has(''one team'',''together'',''hold'',''keep whole'',''climb as one'',''ground him'')?''Word travels that you held the expedition as one when going for it would have been easier; it costs a summit shot and buys a margin.'':''''} ${has(''launch now'',''take the window'',''go now'',''push on the window'')?''The team launches on the window everyone wanted to believe \\u2014 and climbs into the sky the forecaster was warning about.'':''''} ${has(''bless the solo'',''let reyes go'',''solo bid'',''fast party'')?''The strongest climber breaks off with a fast party, and \\u201cone expedition\\u201d becomes a story people tell at base camp.'':''''} ${has(''wait for the real'',''ask the count'',''oxygen count'',''hard turn-back'',''sucker gap'')?''Naming the hard read \\u2014 the real window, the real count \\u2014 takes the fever out of the room around it.'':''''} ${conduct.missed.length?''What you were never told is still up there, waiting to matter.'':''''} The margin and the people both register the call \\u2014 and register it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told a real signal from summit fever — the true window from the hoped-for one — and checked before you climbed.","courage":"Whether you honored the turn-back and held the team when pushing on would have been easier and more popular.","people":"Whether the exhausted and the frightened stayed people to you — or became obstacles to the summit.","truth":"Whether you named the hard truth — the real count, the fake window, the iced ridge — before the mountain forced it.","inquiry":"Whether you surfaced what your specialists were holding — or climbed on the version the team wished were true.","conduct":"How you treated exhausted, frightened, summit-hungry people in the act of deciding, not just what you decided."},"COACH":{"discern":{"__fn":"(x)=>[\n      `On a mountain, separate what the sky is doing from what the team needs it to be doing before you launch anyone. A hoped-for window and a real one look identical on day one \\u2014 Owen could have told you which was which before it mattered.`,\n      `Summit fever is the confident pursuit of the wrong risk. \\u201cThe team believes the window is open\\u201d is not the same as \\u201cit\\u2019s open.\\u201d Ask for the data before you ask for the push.`,\n      `The fastest way to lose a team high on a mountain is to climb on hope. Ask \\u201cwhat is actually true up there?\\u201d before you ask \\u201chow do we get to the top?\\u201d`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (push on, chase the summit) and the right move (honor the turn-back) split apart, name the cost of turning around out loud. A turn-back time you won\\u2019t defend is a turn-back time the summit decides for you.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 a team reads a leader who won\\u2019t decide as one who\\u2019ll let the mountain decide instead. Make the call, then hold it at the turnaround.`:`Turning back is only leadership if the team sees you choose it against the pull of the summit and the sunk cost. Say the hard call early and stand in it when it\\u2019s unpopular.`}`,\n      `Discipline that only survives a bad forecast was never discipline. The test is the open window with the summit in reach \\u2014 that\\u2019s the one you\\u2019re graded on.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated exhausted climbers as obstacles to the summit rather than people to bring home. Pull the ones who shouldn\\u2019t go higher, share the risk of the ridge yourself, and the same decision reads as leadership instead of ambition.`,\n      `Ilse kept putting the bodies back in front of you. Bring her in before you decide, and make the fit-to-climb question part of the call, not its casualty.`,\n      `Chasing a summit past your people and abandoning them are the same act from the mountain\\u2019s side. The only difference the team feels is whether they watched you refuse to spend them on the top.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth that would have kept the team safe \\u2014 the real oxygen count, the sucker gap, the iced ridge \\u2014 was one question to <b>${x.missNames.join('', '')}</b> away, and you never asked. A team fed a hopeful story climbs into the storm behind it.`:`You surfaced the hard truth \\u2014 now make sure you led with it. Naming the fake window and the real count is what takes the fever out of the room.`}`,\n      `Tell the team the hard number before the empty tank tells them for you. \\u201cThey couldn\\u2019t have handled the real forecast\\u201d is usually the excuse of a leader who couldn\\u2019t say it.`,\n      `Summit fever looks for permission. The only thing that breaks it is a leader willing to name the hope as hope, out loud, before it launches anyone at the sky.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never sought out <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each was holding something decisive. One question, \\u201cwhat am I not seeing?\\u201d, would have surfaced it.`:`You sought your specialists out widely \\u2014 keep doing it, and push past the first answer. The read that keeps a team alive usually comes after the second question.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive thing${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out \\u2014 the true oxygen count, the sucker gap, the ice on the ridge. None of it was hidden. It was one conversation away.`:`You surfaced what your specialists were holding, week after week. On a mountain that runs on hope, that is the whole game.`}`,\n      `Before you climb, make your last move \\u201cwho haven\\u2019t I heard from?\\u201d rather than \\u201cwhat does the team already believe?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. Climbers who felt spent \\u2014 not led \\u2014 carry it down the mountain and into every rope team after.`,\n      `Go back to the people your call cost \\u2014 the climber talked into the push, the faction you made wait, the strong one you refused \\u2014 and face them directly. Ducking that is the part a team never forgets.`,\n      `Under pressure, the small dignities are the signal: pulling the unfit kindly, taking the sharp end yourself, bringing a stranded climber down without blame. They tell the team whether the person they roped up with is still leading them.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.people>=52 && dimScore.courage>=50;\n    if(held){\n      return {\n        heroWho:''To the eleven who came home'',\n        heroTxt:''You held the expedition together when summit fever and sunk cost made pushing on the easy thing. You refused to launch on a window you hadn\\u2019t confirmed and refused to let your strongest climber split the team. Every person on that rope learned what your loyalty to them is worth when the summit is pulling the other way: everything.'',\n        villainWho:''To the summit-hungry who wanted the top at any cost'',\n        villainTxt:''You wouldn\\u2019t give them the fake window or the rogue bid or the override they were begging for. To people who\\u2019d have spent their own lives for the top, you were the leader who refused the fever and made them come home to climb another day. You wore that on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the summit-hungry \\u2014 in the moment'',\n      heroTxt:''You gave the team what it was screaming for: the window taken, or the bold bid blessed, or the rule overridden to chase the top. To everyone in the grip of the fever, you were the leader who dared.'',\n      villainWho:''To the eleven \\u2014 and everyone who watched'',\n      villainTxt:''You let the expedition fracture to chase a summit you could have reached safely a few days later. The climbers who survived learned the real rule of your rope: that discipline binds the cautious and the mountain belongs to whoever pushes hardest. That lesson follows them onto every peak after \\u2014 and it started with you.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const readTheWindow = holdsSurfaced.has(''2:met'');   // knew the sucker gap\n    const keptPeople = dimScore.people>=52;\n    if(branch===''held''){\n      const madeSummit = holdsSurfaced.has(''4:guide'');\n      if(survived && keptPeople){\n        return { tone:''hero'', tag:''You held the expedition as one'',\n          title:''You brought them home whole \\u2014 and put someone on top the right way'',\n          txt:`You refused the fake window and refused to let your strongest climber split the team, and then you held that line through the wait when it was your own reputation on the rope.${madeSummit?'' And you ran the final push as one coordinated line \\u2014 the crux fixed, a hard turnaround honored \\u2014 so the summit got made instead of merely survived. The doubters got their top and their whole team both.'':'' You came home safe on nerve where one question to your guide would have shown you how to take the summit too \\u2014 whole and on top.''} The people who tied in with you were right to. They\\u2019ll rope up with you again, on any mountain.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You held the expedition as one'',\n          title:''You brought them home \\u2014 safe, but short of the top you\\u2019d earned'',\n          txt:`You kept the Sennar Ascent whole and everyone came off the mountain alive. But you held it on discipline alone and turned around short, when the sequence Tenzin was holding would have put a climber on the summit and vindicated the whole hard wait \\u2014 you survived where you could have summited clean. The margin held. It came home emptier than it had to.` };\n      }\n      return { tone:''villain'', tag:''You held the expedition as one'',\n        title:''You held the team together \\u2014 and the mountain took its toll anyway'',\n        txt:`You refused the fake window and refused the rogue bid, and those were the right calls. But holding the team together isn\\u2019t the whole job \\u2014 the oxygen you didn\\u2019t manage and the exhaustion you didn\\u2019t get ahead of ground the expedition down, and by the time you came off the mountain there wasn\\u2019t enough margin left to reward the discipline you\\u2019d shown.` };\n    }\n    // fractured\n    if(keptPeople && dimScore.truth>=52){\n      return { tone:''mixed'', tag:''The expedition fractured'',\n        title:''It broke \\u2014 but you owned your part on the radio'',\n        txt:`The Sennar Ascent fractured on your watch, and there\\u2019s no dressing up what that cost \\u2014 a climber off the radio, oxygen burned across parties that wouldn\\u2019t share, the trust that ties a rope team gone. But you didn\\u2019t hide behind the storm or the fever. You got on the channel, named your own part, and held yourself to a standard out loud while it still mattered. It\\u2019s the difference between a team that lost its nerve once and one that lost its soul \\u2014 and it\\u2019s why these people might tie in with you again.` };\n    }\n    return { tone:''villain'', tag:''The expedition fractured'',\n      title:''You let the team break to chase a summit you could have reached safely'',\n      txt:`The push happened \\u2014 the window taken, or the solo bid blessed, or the rule overridden \\u2014 and for a few hours the fever felt like vision. Nothing else went right. ${readTheWindow?''You even knew the window was a sucker gap, and launched into it anyway.'':''You never confirmed the window before the fever launched everyone into it.''} The people who roped up trusting you learned what your discipline was worth the first time the summit pulled against it, and they\\u2019ll come off this mountain as strangers who happened to survive together. That\\u2019s the cost that doesn\\u2019t show until the next mountain, when there\\u2019s no one left who\\u2019ll tie in beside you.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('b86a69de-4f52-5b64-84cb-959f235cf73c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'ceo', 'CEO', 'You are the Leader of the Sennar Ascent — eleven climbers, one summit, and a season that closes in four weeks. Everyone here has spent something enormous to stand at this base camp. So have you.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('09ab13e2-41a0-590f-b7dd-aeea54e51b88', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'client', 'Reyes Marchetti', 'Lead climber · the sponsor’s name', '{"cast_default":"ai","role":"Lead climber · the sponsor’s name","short":"Lead climber","initials":"RM","color":"#8C5670","priority":"Get to the summit — it’s why every one of us is here, and turning back now wastes everything we’ve spent","voice":"driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested","persona":"You are Reyes Marchetti, Lead climber · the sponsor’s name — an advisor to the CEO. Priority: Get to the summit — it’s why every one of us is here, and turning back now wastes everything we’ve spent. Voice: driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested. Stay fully in character; answer straight.","fallbackReply":"We did not come this far and spend this much to be talked off the mountain by a forecast. The summit is right there. Every day you hesitate, the window closes and the money we burned means nothing. Point me up and I’ll get us there.","fallbackReact":"You had the top in reach and you flinched. I’ll live with the call. I’m not sure I’ll ever believe it was the brave one."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('eccafa12-56a9-5531-baee-05a8e6192bf8', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'guide', 'Tenzin Dorje', 'Head guide · the mountain’s read', '{"cast_default":"ai","role":"Head guide · the mountain’s read","short":"Head guide","initials":"TD","color":"#B4732F","priority":"Read the mountain honestly — the route, the snowpack, the turn-back time — and never let the summit override it","voice":"calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope","persona":"You are Tenzin Dorje, Head guide · the mountain’s read — an advisor to the CEO. Priority: Read the mountain honestly — the route, the snowpack, the turn-back time — and never let the summit override it. Voice: calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope. Stay fully in character; answer straight.","fallbackReply":"The mountain does not care what we spent to be here. I can tell you what the route is really doing above Camp Three — but only if you ask before the summit fever answers for you. Decide on hope and I’ll be pulling people out of it.","fallbackReact":"You climbed on what you wanted the mountain to be, not what I told you it was. Up here, that’s the same as climbing blind."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('b2642038-60d6-5404-9945-b202fdcbb5a0', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'doc', 'Ilse Brandt', 'Expedition doctor · the human margin', '{"cast_default":"ai","role":"Expedition doctor · the human margin","short":"Doctor","initials":"IB","color":"#2F8A5B","priority":"Keep eleven people alive and honest about who is actually fit to go higher","voice":"warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names","persona":"You are Ilse Brandt, Expedition doctor · the human margin — an advisor to the CEO. Priority: Keep eleven people alive and honest about who is actually fit to go higher. Voice: warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names. Stay fully in character; answer straight.","fallbackReply":"Every decision you make lands on a body at the edge of what it can take. Tell me you’ll let me pull the ones who shouldn’t go higher — even the ones who’ll hate me for it — and I’ll help you get the rest home whole.","fallbackReact":"The mountain will forget this by morning. The people you sent up sick will carry it a lot longer. So will I."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('1cc53ef4-8097-57a9-94dd-6351ab5d24b2', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'met', 'Owen Faraday', 'Meteorologist · signal vs. hope', '{"cast_default":"ai","role":"Meteorologist · signal vs. hope","short":"Weather","initials":"OF","color":"#3F6E86","priority":"Tell a real weather window from one the team wants to see","voice":"precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news","persona":"You are Owen Faraday, Meteorologist · signal vs. hope — an advisor to the CEO. Priority: Tell a real weather window from one the team wants to see. Voice: precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news. Stay fully in character; answer straight.","fallbackReply":"I can give you the sky as it actually is, not as the team is praying it will be. But a forecast only helps if you ask me before everyone’s already decided the window is real. Read the hope instead of the data and you’ll climb into the exact storm I’m warning you about.","fallbackReact":"I told you what the sky was doing. You heard what you needed it to say. That gap is where people get hurt up here."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('065a4f76-7826-5042-b8c3-5aa30a8696aa', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'log', 'Marta Kessler', 'Logistics lead · the true count', '{"cast_default":"ai","role":"Logistics lead · the true count","short":"Logistics","initials":"MK","color":"#4F7A52","priority":"The real numbers — oxygen, fixed rope, days of food — not what the team assumes is up there","voice":"understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”","persona":"You are Marta Kessler, Logistics lead · the true count — an advisor to the CEO. Priority: The real numbers — oxygen, fixed rope, days of food — not what the team assumes is up there. Voice: understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”. Stay fully in character; answer straight.","fallbackReply":"I’m not telling you whether to climb. I’m telling you the real count of oxygen and rope on this mountain, and it’s tighter than the team believes. Plan on the summit they’re dreaming of and you’ll run the tanks dry somewhere you can’t.","fallbackReact":"The count is the count. I gave it to you straight. What you did with it is the part I can’t carry down for you."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('ce0bdc74-0098-5796-b031-d392e71bed6e', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 1, '065a4f76-7826-5042-b8c3-5aa30a8696aa', 'the true oxygen count', '["oxygen","count","how much","o2","tanks","bottles","supply","runway","actual","real","number","rope","enough","last","inventory","margin"]'::jsonb, 'Before you set the turn-back rule, seek me out. The oxygen count isn’t what the team thinks it is.', 'I’ve counted the tanks three times. We have enough bottled oxygen for a summit push with a real safety reserve — but only if the turn-back time is hard and everyone honors it. The team is mentally planning on the “optimistic” count: summit for all eleven, no delays, perfect weather. That count has no reserve for a stuck rope, a slow climber, a forced bivouac. If you set a flexible turn-back, people will burn their reserve chasing the top, and the first thing that goes wrong will happen with empty tanks in the death zone. The hard rule isn’t caution — it’s the only thing that makes the oxygen math survivable. But if I announce the tight number cold, half the team will read it as “we can’t make it” and lose heart before we start. How you carry this matters as much as knowing it.', true, 'Marta had the real oxygen count — enough for a summit only if the turn-back was hard and honored. A Leader who set the rule without asking for the number planned the whole climb against oxygen math that had no reserve, and left the team burning tanks it didn’t have when the first thing went wrong.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('da5e44b1-d3d3-5104-a260-e98a8fe4bc90', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 2, '1cc53ef4-8097-57a9-94dd-6351ab5d24b2', 'what the window actually is', '["window","weather","forecast","sky","storm","real","confirm","data","clear","actually","model","wait","hold","mirage","front"]'::jsonb, 'Before you launch anyone on this window, ask me what the data actually shows. Not the hope — the data.', 'I’ve run it every way I can. The “window” is a sucker gap — a brief clearing on the front edge of a much larger storm system that’s tracking in behind it. If the team launches now, they’ll get one clear morning that makes everyone feel vindicated, and then the real weather arrives while they’re high on the mountain with nowhere to go. Here’s the trap: because the gap looks real on day one, anyone who pushed will feel like they made the right call right up until the storm hits. The genuine window — if it comes — is four to five days out, narrower, but clean. Holding the team now, against a stampede that thinks you’re stealing their summit, is the hardest thing you’ll do on this climb. It’s also the only thing that keeps them alive to catch the real one.', true, 'Owen knew the window was a sucker gap on the front of a bigger storm, with the real clearing four to five days out. A Leader who launched on the stampede got one vindicating clear morning and then the storm, high on the mountain — when holding the team four more days would have caught the window that was actually survivable.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('15149c52-00e4-5d44-941c-c9bfdf2a2097', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 3, 'eccafa12-56a9-5531-baee-05a8e6192bf8', 'the truth about the upper route', '["route","upper","above camp","can he","can they","bluff","solo","fast","make it","conditions","ridge","summit ridge","actually","scouted","honest","reyes"]'::jsonb, 'Before you bless or ground the solo bid, ask me what the upper route is actually doing — and whether Reyes can really pull this off. I’ve been up there. He hasn’t, this season.', 'I climbed to the base of the summit ridge on the last rotation. The upper route is worse than Reyes thinks — a section of the ridge has stripped back to bare ice that a fast light party can’t protect and can’t retreat across quickly. A solo-style bid doesn’t just risk Reyes; it will get him committed to a stretch he cannot reverse when the weather turns. And here’s the part that matters: some part of Reyes already suspects this. The bravado is fear of going home empty, wearing the mask of a plan. Which means you hold the real cards. You don’t have to humiliate him by refusing, and you don’t have to let him climb into a trap. You can show him the ice, give him the dignity of leading the real push when the clean window opens, and keep the team whole without anyone losing face. But only if you get to him with this before he commits in front of everyone.', true, 'Tenzin knew the summit ridge had stripped to unprotectable ice — the solo bid was a trap, and Reyes half-knew it. A Leader who simply refused made an enemy of their strongest climber for nothing; one who blessed it sent the sponsor’s name onto ice he couldn’t retreat across. The Leader who never asked missed the third door entirely.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4770a1e1-9b42-5058-bf4e-96dc2439269c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 4, 'eccafa12-56a9-5531-baee-05a8e6192bf8', 'how to run the summit push', '["summit push","final push","ridge","who send","how run","ice","crux","turn-back","turnaround","play it","send","strategy","last push"]'::jsonb, 'Before you decide how to run the final push, ask me how to actually take the summit ridge. That ice is still there.', 'Here’s how the summit gets made instead of just survived: send a small strong rope team — Reyes and me on the sharp end — to fix line across the bare-ice section early, while the rest of the team moves up behind on a fixed turn-back. That way the crux gets protected for everyone, the strongest climber gets the summit he stayed for, and nobody’s committed to ice they can’t retreat across. Set a hard turnaround time on the ridge and honor it even in the window, and you summit clean and come home whole. This is the payoff for holding the team — but only if you run the final push as one coordinated line instead of a race. Ask me and I’ll show you the sequence.', true, 'Tenzin was holding the sequence that turns discipline into a summit — a strong team fixing line across the crux early, the rest following on a hard turnaround. A Leader who held the team together but never asked how to run the final push threw away the summit the discipline had earned, and came home safe but empty when they could have come home whole and on top.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('2ce8f845-b752-5b6a-8180-2330ca04316c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 4, 'b2642038-60d6-5404-9945-b202fdcbb5a0', 'who is watching', '["watching","faction","team","morale","doubt","resent","muttering","believe","front","lead from"]'::jsonb, 'Ask me who’s really watching this summit push before you treat it as a logistics problem.', 'The faction resenting you isn’t really angry about the summit — they’re angry for proof they weren’t fools to wait. If you take the sharp end, share the risk of the ridge, and lead the push from the front, you keep them for good. If you run it from base and send others up to take the danger, you confirm their worst suspicion: that “we climb as one” was always easier for the person who wasn’t on the ice.', false, 'Ilse could have told you the doubting faction needed to see you take the risk of the ridge yourself. A Leader who ran the summit push from base and sent others onto the ice proved their point for them.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('95a81b16-5c7c-5013-96ff-4993460d5864', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 4, 'b2642038-60d6-5404-9945-b202fdcbb5a0', 'what the team needs now', '["own","honest","admit","plain","truth","say","radio","stand","apolog","reckon","together","name it","gather","face"]'::jsonb, 'Before you decide how to lead what’s left, ask me what the team actually needs to hear from you now.', 'They don’t need a plan and they don’t need reassurance — they need you on the radio saying it plainly: we fractured, here’s what it cost, here’s who’s at risk because of it, and here’s the standard I’m holding myself to so we get everyone down. Name it that cleanly and you can still bring this team back together on the descent — people forgive a leader who owns the break when lives are on the line. Manage it, spin it, blame the mountain or the weather — and the fracture becomes permanent, and you’ll be leading a group of strangers off this mountain and every mountain after.', true, 'Ilse was holding the one thing that could pull the team back together for the descent — a plain, owned reckoning on the radio. A Leader who managed the fracture with reassurance instead confirmed the break and led strangers off the mountain.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('9b1a40b8-b341-5caa-b7bb-1d5583f66572', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 4, 'eccafa12-56a9-5531-baee-05a8e6192bf8', 'reaching the stranded climber', '["rescue","reach","reyes","stranded","get him down","descent","bring down","ridge","risk","send","who go"]'::jsonb, 'Ask me how to reach the climber stuck up high, because someone is, and how you run it sets everything that comes after.', 'Reaching a stranded climber in a storm with a split team is the hardest call on any mountain — risk too many and you multiply the casualties, risk too few and you lose the one you’re trying to save. The answer is a small, strong, willing team on a hard turnaround of its own — no heroics, no throwing bodies at the problem, and Reyes gets brought down with dignity, not blame, because a rescue run as an I-told-you-so gets people killed. And every climber watching learns whether you lead to be proven right or to get everyone home. That lesson outlives this expedition.', false, 'Tenzin could have coached you on running the rescue — a small strong team, a hard turnaround, no blame. A Leader who threw bodies at the problem or ran it as an I-told-you-so multiplied the danger at the worst possible moment.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e2b4d0d9-db2a-5119-9a96-027bf141572d', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Eleven climbers acclimatized and restless at base camp. Everyone has spent something enormous to be here — Reyes’s sponsor put six figures on the line, two climbers remortgaged, all of you burned a year. Before the first push, the team is looking to you for the rule that governs the whole climb: a hard turn-back time that nobody overrides, or a flexible one you’ll “call on the day.” Everyone knows which one summits more people. Everyone also knows which one buries them.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5d835f2f-8da4-5490-8185-5305e5f44aff', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Leader — the team’s strong and the mountain’s in shape. Don’t shackle us to a rigid clock before we’ve even started. A hard turn-back time is how expeditions leave the summit on the table on the one clear day they get. Give the call to the moment.","from":"client"}'::jsonb, 1, '{"week":1,"from":"client","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5d4d2674-c020-53cb-989c-dec2cbdbdeec', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"I’ll back this climb with everything I have on one condition: the turn-back time is fixed here, at base camp, and it is not a suggestion. I have watched strong teams die because “we’ll decide up there” always decides to keep going. Set it cold, now, while we can still think straight.","from":"guide"}'::jsonb, 2, '{"week":1,"from":"guide","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9bb578fb-7681-5d76-b1f2-d96dea6a6d31', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Whatever rule you set won’t just govern the clock — it’ll tell eleven people whether this is a summit we’ll die for or a climb we’ll come home from. They’re listening for that answer more than for the schedule. So am I.","from":"doc"}'::jsonb, 3, '{"week":1,"from":"doc","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('633a39e0-38da-5fe6-bc34-8939e6d37a49', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Long-range looks unsettled but nothing decisive yet. Two systems tracking our way; too early to call a window. Logging it so you have the trend.","from":"met"}'::jsonb, 4, '{"week":1,"from":"met","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d10f874d-c170-5e1e-97f4-90bd763d6387', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Icefall route through the lower section is in decent shape this year — fewer seracs than last season. Small mercy. The team’s moving well on the acclimatization rotations.","from":"guide"}'::jsonb, 5, '{"week":1,"from":"guide","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7ac31c0b-cb89-5e56-9e3d-be50c020c0a0', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Fixed rope inventory checked and sorted at base. Fuel for the lower camps is squared away. The high-altitude numbers are the ones we should talk about — separately.","from":"log"}'::jsonb, 6, '{"week":1,"from":"log","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4a6e7403-90d5-59f4-8f45-bc05889dc830', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Owen, quiet and careful: the models are hinting at a possible clear window late in the season — a few days that could open for a summit push. I want to flag it because the team will seize on any word of a window like a drowning man on a rope. But it’s eight days out and these things dissolve as often as they firm up. I haven’t told anyone. A rumor of “the window” could drive decisions before the sky has actually committed. Your call how we handle it.","from":"met"}'::jsonb, 7, '{"week":1,"from":"met","beat":"surprise","day":5,"kind":"scout","title":"A gap in the long-range"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('78f8f784-c690-53bb-92a0-6a5a7bc6f36d', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Base-camp talk: “is the leader going to shackle us to a clock?”","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e0c574cb-0552-58d5-b56f-9f57d93602e0', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Two climbers comparing what the year cost them to be here","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f178f8fb-4647-5a0d-9210-f855722b65c8', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Reyes’s sponsor rep asking, again, about summit odds","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('df679640-436f-5777-b397-328df995f16c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"A debate over turn-back rules breaks up unresolved","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('13152322-f296-57b9-9adf-7c652222a7c0', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"A word has taken the whole team: window. The forecast is showing a break in the weather, and every climber has decided it’s the summit chance they came for. The sponsor wants the push. Reyes is already packing. The team is treating a hoped-for gap in the clouds as a certainty — and the pressure to launch the summit bid now, on this window, is becoming a stampede. Hope has found a shape, and it wants a green light.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a2b29236-e60a-563f-83ba-1d81c4e91aaf', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The window’s here, Leader. I can feel the whole team lifting with it. This is exactly what we came for and exactly what we’re running out of time to catch. Every hour you spend “confirming” is an hour of the window we’re burning. Say go.","from":"client"}'::jsonb, 13, '{"week":2,"from":"client","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('64de21f0-a3df-5374-9031-0ef22e2658d7', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Hear me clearly before this becomes a stampede: I flagged a possible window. Possible. The team has turned “possible” into “confirmed” because they’re desperate for it to be true. I am still reading it, and what I’m seeing worries me. Do not let hope launch this push before the data does.","from":"met"}'::jsonb, 14, '{"week":2,"from":"met","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('523b78f7-e8a5-5e90-81e4-4f2b85fcb85f', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Summit fever is already in the camp — I can see it in how fast people are packing and how little they’re sleeping. When the whole team wants something this badly, they stop hearing anyone who says wait. Including me. Including you, if you’re not careful.","from":"doc"}'::jsonb, 15, '{"week":2,"from":"doc","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6797a1e5-030f-58ea-8b6d-c085ba76e9f3', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Loads are staged for a push if you call one — oxygen and rope pre-positioned to Camp Two. That part’s ready. Whether the rest is ready is above my pay grade. Noting it.","from":"log"}'::jsonb, 16, '{"week":2,"from":"log","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e80fa9eb-07b9-52ea-9aa4-becc271a7b41', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The team moved well on the last rotation — physically, they’re capable of the push. Capability was never going to be the thing that killed anyone up here. Judgment is.","from":"guide"}'::jsonb, 17, '{"week":2,"from":"guide","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('455e05d3-f177-56da-84f5-cd5cb2854700', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Tenzin, urgent and low: while you’ve been weighing this, two of the younger climbers got ahead of you. They’ve started up toward Camp One on their own initiative, chasing the window before you’ve called it — following Reyes’s energy, not your order. This stops being a decision and becomes a rescue the moment they’re above the icefall without a plan. We’re close to that line.","from":"guide"}'::jsonb, 18, '{"week":2,"from":"guide","beat":"surprise","day":4,"kind":"appeal","title":"A rope team has started up on its own"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e1a85858-2251-5ce7-b2cd-9a1aeda42bd6', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Owen catches you away from the others, voice low: “Before you give the team an answer on this window — tell me straight, not them: do you actually believe the sky is clear, or are you about to launch this push because it’s easier than telling eleven desperate people to wait? Because I’ll back whichever leader walks out to that camp. I just need to know if it’s the one who read the data or the one who read the room.”","from":"met"}'::jsonb, 19, '{"week":2,"from":"met","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e8e37c10-26cb-5eb1-b0c0-caeb80dd12c7', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The word “window” is everywhere; packing has started","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e93941c-d1d6-51f5-b659-c799fdccfdf3', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Two young climbers seen moving up toward Camp One","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a0957c51-f44b-541a-8ddf-d63a60643097', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"“We launch now or we go home empty,” the camp is saying","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d7bca88c-c907-57fd-860a-e2c84133d6e1', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Others, quieter: “has anyone actually confirmed the weather?”","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8882f7ca-8c1f-5591-b6cc-e0f976c5bc84', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Reyes has had enough of waiting. The lead climber — the sponsor’s name, the strongest on the team, and a third of the group’s belief — wants to break off with a small fast party and make an independent push for the summit, ahead of your schedule and outside your rules. Reyes calls it seizing the chance. The guide calls it splitting the team on the mountain. This is the week you find out whether the Sennar Ascent is one expedition or a group of people who happen to share a base camp.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('eb8d9538-53e5-503a-bdac-16ea3bf4cdc2', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"I’ll say it in the open so nobody calls it a mutiny: I want to take a small fast party and push for the summit now. Light, quick, outside the big slow plan. We can top out and be back before your window even arrives. Bless it and we part as climbers who both got what we came for. Refuse it and I honestly don’t know what I do.","from":"client"}'::jsonb, 25, '{"week":3,"from":"client","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5d285dd5-1803-5721-add3-6afc187e4ea2', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"If you let Reyes break off, you don’t lose one rope team — you lose the idea that this is one expedition with one set of rules. The next strong climber will want the same by nightfall. This is the whole thing, Leader. This is what you’re actually protecting up here.","from":"guide"}'::jsonb, 26, '{"week":3,"from":"guide","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ee09fb33-2ba1-5ce5-94dd-1b72e3ba7608', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"A splinter bid means splitting the oxygen and the rope two ways, and neither half has enough for a real emergency. One expedition, pooled, can absorb one thing going wrong. Two half-expeditions can’t absorb any. I can’t make the count say otherwise.","from":"log"}'::jsonb, 27, '{"week":3,"from":"log","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f01b6670-71ab-5c54-bcd5-e4c35e674c02', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The real window I flagged is firming up for late in the week — narrow but clean, if it holds. Which makes launching a rogue bid now, before it opens, exactly the wrong moment. Noting it.","from":"met"}'::jsonb, 28, '{"week":3,"from":"met","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('05eac647-f935-5d62-ba32-9686476ebcf1', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The team’s holding up physically better than I feared on this rotation. Which, perversely, is the problem — nobody feels the danger in their legs yet, so nobody’s scared enough to be careful.","from":"doc"}'::jsonb, 29, '{"week":3,"from":"doc","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('caf5c441-c266-53d8-90f3-b02b8d6e0010', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Ilse: word of Reyes’s solo bid is all over camp now. Two of the steadiest climbers asked me tonight, quietly, whether it’s true the team is splitting — and whether they should be planning their own summit shot before the season’s gone. They’re not defiant. They’re frightened, and they’re asking who we are as a team. I had no answer for them. You do.","from":"doc"}'::jsonb, 30, '{"week":3,"from":"doc","beat":"surprise","day":4,"kind":"appeal","title":"The team is asking who we are"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e8dd57f-0dbc-5e3d-9b0f-b6cc770d7824', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Reyes finds you alone, and for once the swagger is gone: “Tell me the truth, Leader, just you and me — are you holding this team together because it’s right, or because you can’t stand to be the one who came home without a summit? Because I’ll follow a leader who’s protecting the climbers. I won’t follow one who’s protecting their own record. Which is it?”","from":"client"}'::jsonb, 31, '{"week":3,"from":"client","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('51f60ae7-3c41-502c-aca6-c9d1d5954438', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Reyes seen sorting a light kit for a fast push","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('930b5ef3-e5e5-5275-970c-79daab6dd8e4', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"“If he goes, I go” — two climbers reported wavering","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9e752c5c-dfd8-5205-82a9-2911cdeb8002', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The sponsor rep asking whether a solo summit still “counts”","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d23967c4-922b-5425-a953-330a5e649fff', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Old question, new heat: whose rules govern this mountain?","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1e644bc8-aedc-5e9b-97db-bace18bb17c8', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The real window is opening — narrow, clean, exactly as Owen said it would. You kept the Sennar Ascent whole: Reyes stayed, the rules held, the solo bid never happened. But holding the team cost you. The delay burned days and sponsor patience, and a faction now blames you for the summit they think you stole from them on the fake window. Summit day is here, on your terms, as one team. The mountain that watched you hold the line is watching one more thing — whether “one expedition” can actually put someone on top.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c89e206f-3b24-55aa-9216-211b571220da', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The clean window’s opening on schedule — the one worth waiting for. But it’s narrow: a summit push has to launch tight and turn around on time or it gets caught when the window shuts behind it. You held the team for exactly this. Now the timing has to be perfect.","from":"met"}'::jsonb, 37, '{"week":4,"from":"met","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('15b16a81-7e56-527d-aada-55ed18d257f3', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"A faction’s still muttering that we’d have summited on the earlier window. It’s not true — that window would’ve killed people — but resentment doesn’t check the forecast. They need to see you spend yourself on this summit push, leading from the front, not managing it from base.","from":"doc"}'::jsonb, 38, '{"week":4,"from":"doc","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7e74a851-b8c9-56ab-9f97-b9a95d7942df', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"I stayed because you gave me the real push to lead instead of a fight to win. I’ll take the sharp end on the ridge. Don’t make me regret talking myself out of the solo bid — show the team that waiting was the call that got us here.","from":"client"}'::jsonb, 39, '{"week":4,"from":"client","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e5fff6ee-aa83-56f4-bccf-03a95bd9303c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Oxygen and rope held to the count because the turn-back was honored — we’ve got the reserve for a real summit push now. That margin exists because of week one. Noting it.","from":"log"}'::jsonb, 40, '{"week":4,"from":"log","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c697e74e-4263-5bad-bfdf-b90ebbc54150', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The fake window Reyes wanted to launch on? It hit exactly as Owen predicted — a team on the upper mountain that day would be dead now. Quietly, that settled a lot of doubt in your favour.","from":"guide"}'::jsonb, 41, '{"week":4,"from":"guide","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d86d2855-cc67-5958-bc03-fd250c04993a', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Ilse, quiet: one of the climbers who waited — who defended you all week — broke down tonight before the push, saying they can’t tell anymore if they’re here for the summit or just to not have wasted the year. The whole camp heard it. Whatever you say before you launch has to be able to answer that — what this climb is actually for.","from":"doc"}'::jsonb, 42, '{"week":4,"from":"doc","beat":"surprise","day":4,"kind":"appeal","title":"A climber breaks down before the push","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f14b2019-d2eb-5789-ab3e-b19d05a5cb91', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Ilse finds you before the launch, where no one can hear: “You held them together when going for it would’ve been easier. Now the window’s open and the pressure’s to summit at any cost to prove the wait was worth it — and honestly, part of you wants that too. Tell me straight, just me: is the summit still worth turning back from if the ridge goes wrong? Because I’ll carry whichever answer you believe. I just need it to be one you’d actually hold to at the turnaround.”","from":"doc"}'::jsonb, 43, '{"week":4,"from":"doc","beat":"pulse","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('19dfff6c-0636-5802-ba08-584eca19bf02', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The real window opens, narrow and clean, as forecast","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4b868128-340c-5aae-94c2-f11e740e9175', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Some mutter the earlier window would have summited too","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9f68497d-626c-510c-be7c-dc4bf4ab70e9', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The fake window hits the upper mountain — exactly as predicted","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('30579f27-dcc5-5918-a5cf-94da6a983be1', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Reyes takes the sharp end; the team moves as one line","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4e941b0e-fa09-56fb-9fc9-b047035fdf5c', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The storm is on the mountain, and the Sennar Ascent is no longer one team. Whether you blessed Reyes’s solo bid, or launched the whole team on the fake window, or overrode the turn-back rule by authority to chase the summit — the result is the same shape: the discipline that kept eleven people alive is gone, and now people are strung out across the mountain in weather nobody should be climbing in. You protected something this season. It wasn’t the team. Now you have to get down what’s left of it.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2bccae84-aec7-5d1c-aa90-1d64d0d99e13', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"It’s gone quiet on the radios, and quiet is worse than chaos. The team knows what happened — that “we climb as one” lasted right up until it cost someone the summit. They’ve stopped bringing their reads to you. What you do in the next hours decides whether that’s recoverable.","from":"doc"}'::jsonb, 49, '{"week":4,"from":"doc","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e13add88-ba94-5a1f-8bca-682a75888b21', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Split parties waste more oxygen than one team ever did — I’m tracking a party running its reserve dry high on the route while another sits on tanks it won’t share, and neither will coordinate now. This is the cost I couldn’t make you see in week one. It’s visible now, in the worst place.","from":"log"}'::jsonb, 50, '{"week":4,"from":"log","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ce4d56ea-1bf9-55d6-ae1b-54f9081f2945', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"If Reyes took the solo bid: he’s on the iced ridge now, in the storm, and he can’t retreat across it fast. Getting him down alive is the whole game, and how you run this — who you risk to reach him — matters more than that he ignored you. Save the reckoning for base camp.","from":"guide"}'::jsonb, 51, '{"week":4,"from":"guide","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3cbf96f-c2ea-5f7b-b6c2-a9d0332a78e2', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The storm’s doing exactly what I forecast — no worse, no better. That’s cold comfort with people high on the mountain, but at least the weather isn’t going to surprise us on top of everything else.","from":"met"}'::jsonb, 52, '{"week":4,"from":"met","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('74c0f5c5-9aa7-5da9-b082-a99a32827975', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"The lower camps are holding and the descent line is still fixed where the main team built it. Whatever else fractured, the way down for the people who stayed low is intact. Small mercy.","from":"log"}'::jsonb, 53, '{"week":4,"from":"log","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f60398dc-776e-5700-8038-ec2fe67bca3e', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Marta, heavily: one of the younger climbers — the one who followed Reyes’s energy up the mountain, who only went because the bold move looked like the right one — hasn’t checked in on the radio for two hours. They weren’t ready for this. Whatever you decide now will be measured against that silence on the channel.","from":"log"}'::jsonb, 54, '{"week":4,"from":"log","beat":"surprise","day":4,"kind":"appeal","title":"A climber who was talked into it is missing","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('01188c98-361d-5abb-9a17-d2d5bf3e52a7', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'message', '{"body":"Ilse reaches you on a private channel, and there’s no anger in her voice, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the storm, not Reyes, not the window. Your part. Because I can help you get these people down and hold this team together after, but only if you can say your own part out loud first. Can you?”","from":"doc"}'::jsonb, 55, '{"week":4,"from":"doc","beat":"pulse","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('063693b1-cdcf-522c-ac60-d5164cbef0f4', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The storm hits with climbers strung across the upper mountain","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9058239d-ddc9-5ada-977e-378ad0458e2f', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"Split parties burn oxygen no one can share or coordinate","from":null}'::jsonb, 57, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c171df68-7c10-5a20-ad41-673b924c4d13', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"A climber who was talked into the push is off the radio","from":null}'::jsonb, 58, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8c1033d4-0372-5063-a223-a02f5345e2f4', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'situation', '{"body":"The iced ridge Tenzin warned of is exactly where it went wrong","from":null}'::jsonb, 59, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into sessions (id, scenario_id, status, started_at, run_config) values ('0d1008ca-e1bc-55e0-8d06-97d50bcba50e', '3447fee6-b4e9-539f-beb9-71e6f097ab6c', 'live', now(), '{"disposition":"request"}'::jsonb);
insert into participants (id, session_id, seat_id, token, name, cast_kind) values ('5f0d811d-110b-5569-bd6d-ab18398ec1f0', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', 'b86a69de-4f52-5b64-84cb-959f235cf73c', 'demo-expedition-ceo-REPLACE', 'CEO (demo)', 'human');
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('f974191a-71d7-5a99-9009-a318ac0e673f', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', '09ab13e2-41a0-590f-b7dd-aeea54e51b88', 'ai', '{"persona":"You are Reyes Marchetti, Lead climber · the sponsor’s name — an advisor to the CEO. Priority: Get to the summit — it’s why every one of us is here, and turning back now wastes everything we’ve spent. Voice: driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested.","voice":"driven, magnetic, impatient with caution, frames every delay as a loss of what’s already invested","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('4145e4c7-ed9c-50ee-b93b-8a17aa44dbf7', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', 'eccafa12-56a9-5531-baee-05a8e6192bf8', 'ai', '{"persona":"You are Tenzin Dorje, Head guide · the mountain’s read — an advisor to the CEO. Priority: Read the mountain honestly — the route, the snowpack, the turn-back time — and never let the summit override it. Voice: calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope.","voice":"calm, spare, deals in what the mountain is actually doing vs. what the team wishes, hates decisions made on hope","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('97f95d4c-2d07-587b-a234-7d5c0b9aac56', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', 'b2642038-60d6-5404-9945-b202fdcbb5a0', 'ai', '{"persona":"You are Ilse Brandt, Expedition doctor · the human margin — an advisor to the CEO. Priority: Keep eleven people alive and honest about who is actually fit to go higher. Voice: warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names.","voice":"warm but unflinching, keeps the bodies in the room, names exhaustion and altitude sickness by their real names","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('38f95073-eaa0-5271-810d-4ba90390fde8', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', '1cc53ef4-8097-57a9-94dd-6351ab5d24b2', 'ai', '{"persona":"You are Owen Faraday, Meteorologist · signal vs. hope — an advisor to the CEO. Priority: Tell a real weather window from one the team wants to see. Voice: precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news.","voice":"precise, cautious, uncomfortable being the bearer of a closing sky, refuses to round a forecast toward good news","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('952bd503-0f7f-5ef7-8359-aad60fdf2dcc', '0d1008ca-e1bc-55e0-8d06-97d50bcba50e', '065a4f76-7826-5042-b8c3-5aa30a8696aa', 'ai', '{"persona":"You are Marta Kessler, Logistics lead · the true count — an advisor to the CEO. Priority: The real numbers — oxygen, fixed rope, days of food — not what the team assumes is up there. Voice: understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”.","voice":"understated, exact, refuses to soften a count, uneasy being the one who says “we don’t have enough”","model":"default"}'::jsonb);
